            if "'" in subject:
                subject = subject.split("'")[0]
            if subject not in subject_to_parts:
                subject_to_parts[subject] = []
            subject_to_parts[subject].append(part)

        # Build sentence with relative clauses where possible
        # Start with the first part
        sentence = parts[0]

        # Track which subjects have been mentioned to avoid redundancy
        mentioned_subjects = set()
