        if "'" in first_subject:
            first_subject = first_subject.split("'")[0]
        mentioned_subjects.add(first_subject)

        # Chain remaining parts with relative clauses when subjects match
        for i in range(1, len(parts)):
            part = parts[i]
            # Extract subject from this part
            part_subject = part.split()[0] if part.split() else ""
            if "'" in part_subject:
                part_subject = part_subject.split("'")[0]

            # Use relative clause if subject was already mentioned
            if part_subject in mentioned_subjects:
                # Convert to relative clause (remove subject repetition)
                if i == len(parts) - 1:
                    # Last part - use "and which" or "and where"
                    if "is located" in part or "is in" in part or "is part of" in part:
                        sentence += ", and where " + " ".join(part.split()[2:])
                    elif "capital" in part or "leader" in part or "mayor" in part:
                        sentence += ", and where " + " ".join(part.split()[2:])
                    else:
                        sentence += ", and which " + " ".join(part.split()[2:])
                else:
                    # Middle part - use "which" or "where"
                    if "is located" in part or "is in" in part or "is part of" in part:
                        sentence += ", where " + " ".join(part.split()[2:])
                    elif "capital" in part or "leader" in part or "mayor" in part:
                        sentence += ", where " + " ".join(part.split()[2:])
                    else:
                        sentence += ", which " + " ".join(part.split()[2:])
            else:
                # New subject - use ", and"
                if i == len(parts) - 1:
                    sentence += ", and " + part
                else:
                    sentence += ", " + part

            mentioned_subjects.add(part_subject)

        sentence += "."

    # Ensure the first character is capitalised
    sentence = sentence[0].upper() + sentence[1:]
    return sentence

